import { useState } from "react";

function CreatePostModal({ isOpen, onClose }) {
  const [content, setContent] = useState("");
  const [images, setImages] = useState([]);

  if (!isOpen) return null;

  // Handle Image Upload
  const handleImages = (e) => {
    const files = Array.from(e.target.files);

    // Multiple images add
    setImages((prev) => [...prev, ...files]);
  };

  // Remove Image
  const removeImage = (index) => {
    const updated = [...images];
    updated.splice(index, 1);
    setImages(updated);
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">

      {/* Modal */}
      <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl max-h-[90vh] flex flex-col overflow-hidden">

        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b">

          <h2 className="text-xl font-bold">
            Create Post
          </h2>

          <button
            onClick={onClose}
            className="w-10 h-10 rounded-full bg-gray-100 hover:bg-gray-200 transition"
          >
            ✕
          </button>

        </div>

        {/* Scrollable Content */}
        <div className="overflow-y-auto p-4 flex-1">

          {/* User Info */}
          <div className="flex items-center gap-3">

            <div className="w-12 h-12 rounded-full bg-blue-600 text-white flex items-center justify-center font-bold">
              A
            </div>

            <div>

              <h4 className="font-semibold">
                Akkas
              </h4>

              <select className="bg-gray-100 px-3 py-1 rounded-lg text-sm outline-none">

                <option>Public</option>

                <option>Private</option>

              </select>

            </div>

          </div>

          {/* Textarea */}
          <textarea
            value={content}
            onChange={(e) => setContent(e.target.value)}
            placeholder="What's on your mind?"
            className="w-full mt-5 min-h-[120px] resize-none outline-none text-lg"
          />

          {/* Image Preview */}
          {images.length > 0 && (

            <div className="grid grid-cols-2 gap-3 mt-4">

              {images.map((img, index) => (

                <div
                  key={index}
                  className="relative"
                >

                  <img
                    src={URL.createObjectURL(img)}
                    alt="preview"
                    className="w-full h-40 object-cover rounded-xl"
                  />

                  {/* Remove Button */}
                  <button
                    onClick={() => removeImage(index)}
                    className="absolute top-2 right-2 bg-black/60 text-white w-7 h-7 rounded-full text-sm hover:bg-black"
                  >
                    ✕
                  </button>

                </div>

              ))}

            </div>

          )}

          {/* Upload Box */}
          <label className="border-2 border-dashed border-gray-300 rounded-2xl p-6 flex flex-col items-center justify-center cursor-pointer hover:bg-gray-50 transition mt-5">

            <span className="text-3xl">
              📷
            </span>

            <p className="text-gray-500 mt-2 text-center">
              Add Photos / Videos
            </p>

            <input
              type="file"
              hidden
              multiple
              accept="image/*"
              onChange={handleImages}
            />

          </label>

        </div>

        {/* Footer */}
        <div className="p-4 border-t">

          <button className="w-full bg-blue-600 hover:bg-blue-700 transition text-white py-3 rounded-xl font-semibold">
            Post
          </button>

        </div>

      </div>

    </div>
  );
}

export default CreatePostModal;
